import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.CMAFtOGK.js";const p=JSON.parse('{"title":"03 新民主主义革命","description":"政治理论 · 03 新民主主义革命","frontmatter":{"title":"03 新民主主义革命","description":"政治理论 · 03 新民主主义革命","category":"politics-note"},"headers":[],"relativePath":"posts/politics/notes/03-新民主主义革命.md","filePath":"posts/politics/notes/03-新民主主义革命.md","lastUpdated":1784753089000}'),r={name:"posts/politics/notes/03-新民主主义革命.md"};function s(n,t,i,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="_03-新民主主义革命理论" tabindex="-1">03 新民主主义革命理论 <a class="header-anchor" href="#_03-新民主主义革命理论" aria-label="Permalink to &quot;03 新民主主义革命理论&quot;">​</a></h1><blockquote><p>🎯 <strong>一句话</strong>：无产阶级领导的，人民大众的，反对帝国主义、封建主义和官僚资本主义的革命。</p></blockquote><hr><h2 id="一、总路线-必背" tabindex="-1">一、总路线（必背） <a class="header-anchor" href="#一、总路线-必背" aria-label="Permalink to &quot;一、总路线（必背）&quot;">​</a></h2><p><strong>无产阶级领导的，人民大众的，反对帝国主义、封建主义和官僚资本主义的革命。</strong></p><h3 id="对象-动力-领导-性质-前途" tabindex="-1">对象 / 动力 / 领导 / 性质 / 前途 <a class="header-anchor" href="#对象-动力-领导-性质-前途" aria-label="Permalink to &quot;对象 / 动力 / 领导 / 性质 / 前途&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">要素</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">对象</td><td style="text-align:left;">帝、封、官（三座大山）</td></tr><tr><td style="text-align:left;">动力</td><td style="text-align:left;">工人阶级、农民阶级、城市小资产阶级、民族资产阶级</td></tr><tr><td style="text-align:left;">领导</td><td style="text-align:left;"><strong>工人阶级</strong>（通过共产党）—— 区分新旧民主革命的根本标志</td></tr><tr><td style="text-align:left;">性质</td><td style="text-align:left;">资产阶级民主主义革命（新式）</td></tr><tr><td style="text-align:left;">前途</td><td style="text-align:left;">社会主义</td></tr></tbody></table><hr><h2 id="二、三大法宝" tabindex="-1">二、三大法宝 <a class="header-anchor" href="#二、三大法宝" aria-label="Permalink to &quot;二、三大法宝&quot;">​</a></h2><ol><li><strong>统一战线</strong></li><li><strong>武装斗争</strong></li><li><strong>党的建设</strong></li></ol><hr><h2 id="三、道路与基本纲领" tabindex="-1">三、道路与基本纲领 <a class="header-anchor" href="#三、道路与基本纲领" aria-label="Permalink to &quot;三、道路与基本纲领&quot;">​</a></h2><ul><li><strong>道路</strong>：农村包围城市、武装夺取政权</li><li><strong>政治纲领</strong>：建立无产阶级领导的各革命阶级联合专政的民主共和国</li><li><strong>经济纲领</strong>：没收封建地主土地归农民；没收官僚资本归新民主主义国家；保护民族工商业</li><li><strong>文化纲领</strong>：民族的、科学的、大众的文化</li></ul><hr><h2 id="四、闭卷挑战" tabindex="-1">四、闭卷挑战 <a class="header-anchor" href="#四、闭卷挑战" aria-label="Permalink to &quot;四、闭卷挑战&quot;">​</a></h2><p><strong>1.</strong> 区分新旧民主主义革命的根本标志是什么？</p><blockquote><p><strong>点击查看答案与解析</strong> 领导权是否掌握在无产阶级（共产党）手中。</p></blockquote><p><strong>2.</strong> 新民主主义革命的三大法宝是什么？</p><blockquote><p><strong>点击查看答案与解析</strong> 统一战线、武装斗争、党的建设。</p></blockquote><p>返回：02-毛泽东思想 · <a href="/zhuan-sheng-ben-notes/posts/politics/">政治</a></p>',20)])])}const _=e(r,[["render",s]]);export{p as __pageData,_ as default};
